script:
frappe.ui.form.on("Custom Applicant Form", {
    refresh(frm) {
        restrict_document_columns(frm);
    },
    onload(frm) {
        restrict_document_columns(frm);
    }
});

function restrict_document_columns(frm) {
    // Check if current user has Student role
    if (frappe.user_roles.includes("Student")) {
        // Hide these columns in the child table — student only sees Attach
        frm.fields_dict["student_documents"].grid.toggle_display("document_name", false);
        frm.fields_dict["student_documents"].grid.toggle_display("is_mandatory", false);
        frm.fields_dict["student_documents"].grid.toggle_display("document_status", false);
        frm.fields_dict["student_documents"].grid.toggle_display("purpose", false);
        frm.fields_dict["student_documents"].grid.toggle_display("remarks", false);

        // Prevent student from adding or deleting rows
        frm.fields_dict["student_documents"].grid.cannot_add_rows = true;
        frm.fields_dict["student_documents"].grid.wrapper.find(".grid-remove-rows").hide();
        frm.fields_dict["student_documents"].grid.wrapper.find(".grid-remove-all-rows").hide();
        frm.refresh_field("student_documents");
    }
}
